var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"진짜로 괜찮겠어?","JPN":"本当にいいの？","ENG":"Are you sure about this?","TWN":"真的沒關係嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"음식 같은 거 먹으면 안 되는데, 내가 연습했다고 해서 괜히 무리하는 건 아니지?","JPN":"本当は食べちゃダメなのに、私が練習したからって無理してない？","ENG":"You're not supposed to eat food. You're not just forcing yourself because I practiced, are you?","TWN":"你不能吃東西的吧？是不是因為我說練習了，你才吃的啊？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"괜찮아. 영양섭취가 불필요하다 하여 그것을 즐기지 못하는 건 아니니까.","JPN":"いいのだ。栄養の摂取が不要とはいえ、食を楽しめないわけではないからな。","ENG":"It's fine. I may not need food to survive, but that doesn't mean I can't enjoy it.","TWN":"沒關係。即使不需要攝取營養，也不代表不能享受美食。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"맛도 다 느낄 수 있는 거야?","JPN":"味もちゃんと分かるの？","ENG":"And you can still taste everything?","TWN":"可以嚐出來味道嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"맛을 느끼는 건 인공감각수용체지만, 맛있는 걸 먹었을 때 기쁜 것은 틀림없는 본인일세.","JPN":"味を感じるのは人工感覚受容体だが、美味いものを食べて嬉しいと思うのは、間違いなく某自身だ。","ENG":"The taste comes from artificial receptors, but the joy of good food is still mine.","TWN":"雖然感受到味道的是人工感官受體，但我吃到美味的東西還是會感到開心。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…어때? 맛있어?","JPN":"……どう？　美味しい？","ENG":"...So? How is it? Good?","TWN":"……怎麼樣？好吃嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"걱정 말게. 내 쪽에서 염분수용감각의 예민도를 35% 정도 낮추면 될 일이야.","JPN":"心配はいらん。某が塩分受容感覚の敏感度を35％程下げればいいことだ。","ENG":"Don't worry. I can just dial down my salt sensitivity by about thirty-five percent.","TWN":"別擔心。我只需將鹽分感知的敏感度降低35%就行了。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"좀 짜다는 거지? 거 되게 솔직하시네요.","JPN":"それ、塩っぱいってことだよね？　正直な感想ありがと。","ENG":"So it is salty? Wow, you really don't hold back.","TWN":"有點鹹是吧？你還真是坦率呢。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…만일 내가 살아있었다면, 이 짠 맛에 사무쳐 울음을 터뜨렸을 지도 모르겠군.","JPN":"……もし某が生きていたら、この塩っぱさが身に染みて涙を流していたかもしれんな。","ENG":"...If I were still alive, this saltiness alone might have brought me to tears.","TWN":"…如果我還活著，可能會因為這鹹味忍不住哭出來吧。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그, 그 정도야?","JPN":"そ、そんなに？","ENG":"I-it's that much?","TWN":"有……有那麼誇張嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"다시… 만들까?","JPN":"作り……直そうか？","ENG":"Should I... make new ones?","TWN":"要不我還是重新做一份吧？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"맛없다는 게 아닐세. 그만큼이나 그리웠던 것 같아.","JPN":"不味いという意味ではない。どうやら某はそれほど懐かしかったようだ。","ENG":"I never said it was bad. I think it's simply that I've missed this...","TWN":"不是說不好吃，我只是很懷念。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"식탁에 이리 둘러앉아 두런두런 나누는 이 따스한 온기를.","JPN":"こうして食卓を囲み、話し合う時間の温かいぬくもりが。","ENG":"This warmth of sitting around a table, talking together like this.","TWN":"懷念我們圍在餐桌旁的溫暖。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"시윤 군은 어떤가? 앤디의 진수성찬.","JPN":"シリュウ君はどうだ？　アンディーの料理。","ENG":"And you, Shiyoon? What do you think about Andy's grand feast?","TWN":"時雲覺得安狄準備的豐盛的飯菜怎麼樣？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아하하, 두 분을 방해하고 싶지 않아서 조용히 먹고만 있었는데 말이죠.","JPN":"ハハ、お二人を邪魔したくないと思って、黙って食べていましたが。","ENG":"Ahaha, I kept quiet because I didn't want to interrupt the two of you.","TWN":"啊哈哈，我本打算安靜地吃，不想打擾你們兩位。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"표현하자면 그리운 집밥의 맛이랄까요? 정성이 느껴져서 좋네요.","JPN":"あえて表現するなら、懐かしい家庭料理の味って感じですね。真心が伝わってきます。","ENG":"But if I had to describe it... I'd say it tastes like home cooking. Nostalgic, heartfelt.","TWN":"如果要形容的話，就像是久違的家常菜的味道吧？能感受到她的用心，很好吃。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그냥 맛있다 한 마디면 될 텐데. 두 사람 다 쉬운 길로 갈 생각이 없구나?","JPN":"一言、美味しいでいいのに。二人とも小難しい言い回しが好きなんだね？","ENG":"You could've just said it was good. Do neither of you know how to take the easy route?","TWN":"就說好吃不行嘛？你們兩個真的是。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"시윤 군의 반응은 제법 호평이라 생각했는데 말이지.","JPN":"シリュウ君の感想はかなり好評に近いと思ったのだが。","ENG":"I thought Shiyoon's reaction sounded quite favorable.","TWN":"我以為時雲是在誇獎呢。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아무래도 서생 씨의 혹평 때문에 이미 상처받으신 게 아닐까요?","JPN":"ショウさんの酷評で、既に傷ついていたんじゃないでしょうか？","ENG":"Maybe it's because your harsh critique already hurt her feelings.","TWN":"恐怕是因為書生的苛刻評價，讓她受傷了吧？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"크흠, 미안하군.","JPN":"ゴホン……すまない。","ENG":"Ahem. My apologies.","TWN":"咳咳，抱歉了。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"됐어. 결국 제일 좋아하는 음식을 맛있게 못 만들어준 내가 원인이지 뭐.","JPN":"いいよ。一番の好物を美味しく作ってあげられなかった私が悪いんだから。","ENG":"Forget it. The real problem's me not being able to cook his favorite dish the way it should be.","TWN":"算了算了，最終還是因為我沒能做好是吧。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아, 갈비찜 다 됐나보다. 금방 다녀올게.","JPN":"あ、肉じゃがが出来上がったみたい。ちょっと待ってて。","ENG":"Ah, sounds like the galbi-jjim's done. Be right back.","TWN":"啊，燉排骨應該好了，我去拿過來。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그나저나 신기하네요. 저희 아버지도 계란찜을 제일 좋아하셨거든요.","JPN":"それにしても、奇遇ですね。僕のお父さんも茶碗蒸しが一番の好物だったんです。","ENG":"Funny, my father's favorite was steamed egg too.","TWN":"不過真神奇啊，我父親也最喜歡吃蒸蛋呢。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"세상이 변해도, 기호라는 건 쉽게 바뀌지 않나 봐요.","JPN":"世の中が変わっても、人の嗜好はそう簡単に変わらないものなんですかね。","ENG":"I guess some preferences never change, no matter how the world does.","TWN":"即使世界改變，喜好似乎也不容易改變呢。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"기호라…","JPN":"嗜好か……","ENG":"Preferences, you say...","TWN":"喜好啊…"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"시윤 군은 혹시 곶감을 좋아하는가?","JPN":"シリュウ君は、干し柿は好きだろうか。","ENG":"Do you like dried persimmons, Shiyoon?","TWN":"時雲喜歡柿餅嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};